#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""deploy_signalfix.py — Part B(1/2) 信号质量修复（趋势+叙事+判定逻辑）

1. china_public_opinion: SentimentAssessment before-validator —— DeepSeek 返回变体
   {market_sentiment,key_risks,summary} 时映射+补默认，解析成真实信号而非退中性。
2. china_policy: PolicyImpact 同理（漏 has_relevant_policy/signal 时容错）。
3. decision_summary: 数据不足判定改为"以 reasoning 真实数据错误为准"而非单纯低置信
   （technical 弱信号不再被误杀），移除误导性"代理劫持东财"告警，
   改为诚实的"估值/资金/板块需国内VPS/代理通道"。

不含 UI（i18n/K线/池/日报）—— 下一轮。
用法: poetry run python deploy_signalfix.py     回滚: deploy_backup/<时间戳>/ 覆盖回去
"""
import base64, os, sys, shutil, types
from datetime import datetime

FILES = {
    'src/agents/china_public_opinion.py': "",
    'src/agents/china_policy.py': "",
    'src/utils/decision_summary.py': "",
}

def main():
    root = os.getcwd()
    if not os.path.isdir(os.path.join(root, "src")):
        print("[FAIL] 请在项目根目录(含 src/)运行"); sys.exit(1)
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bdir = os.path.join(root, "deploy_backup", ts); os.makedirs(bdir, exist_ok=True)
    for rel, b64 in FILES.items():
        dst = os.path.join(root, *rel.split("/"))
        if os.path.exists(dst):
            shutil.copy2(dst, os.path.join(bdir, rel.replace("/", "__")))
        with open(dst, "wb") as f:
            f.write(base64.b64decode(b64))
        print(f"[OK] 写入 {rel}")
    print(f"[OK] 备份 -> deploy_backup/{ts}/")
    n = 0
    for r,_,_ in os.walk(os.path.join(root,"src")):
        if r.endswith("__pycache__"): shutil.rmtree(r, ignore_errors=True); n+=1
    print(f"[OK] 清理 {n} 个 __pycache__")
    verify(root)

def verify(root):
    print("-"*60); print("验证(真实坏JSON回归, 自带stub不依赖完整环境):")
    sys.path.insert(0, root)
    # stub 重依赖, 只验证 validator 逻辑本身
    def _stub(name, **a):
        m = types.ModuleType(name); [setattr(m,k,v) for k,v in a.items()]; sys.modules[name]=m
    class _D:
        def __init__(s,*a,**k): pass
        def __getattr__(s,n): return _D()
        def __call__(s,*a,**k): return _D()
        @classmethod
        def from_messages(cls,*a,**k): return _D()
    for mod in ("langchain_core","langchain_core.prompts","langchain_core.messages"):
        _stub(mod)
    sys.modules["langchain_core.prompts"].ChatPromptTemplate = _D
    sys.modules["langchain_core.messages"].HumanMessage = _D
    sys.modules["langchain_core.messages"].BaseMessage = _D
    _stub("src.utils.llm", call_llm=lambda *a,**k: None)
    pm = types.ModuleType("src.utils.progress"); pm.progress = _D(); sys.modules["src.utils.progress"]=pm
    for m in [m for m in list(sys.modules) if "china_public_opinion" in m or "china_policy" in m or "decision_summary" in m]:
        del sys.modules[m]
    try:
        from src.agents.china_public_opinion import SentimentAssessment
        sa = SentimentAssessment.model_validate({"market_sentiment":"负面","summary":"情绪偏负面"})
        assert sa.signal == "bearish"
        print("  [PASS] 舆情: DeepSeek '负面' -> signal=bearish (不再退中性)")
        from src.agents.china_policy import PolicyImpact
        pi = PolicyImpact.model_validate({"signals":[{"direction":"利空"}],"overall_impact":"利空","reasoning":"利空"})
        assert pi.signal == "bearish" and pi.has_relevant_policy is True
        print("  [PASS] 政策: DeepSeek '利空'+漏字段 -> signal=bearish has_policy=True")
        import importlib
        ds = importlib.import_module("src.utils.decision_summary")
        r = ds._collect("X", {"technical_analyst_agent":{"X":{"signal":"neutral","confidence":15,"reasoning":"trend weak momentum flat"}}})
        assert not ds._is_data_starved(r[0])
        print("  [PASS] 判定: technical 15% 真实弱信号 -> 有效(不再误杀)")
    except Exception as e:
        import traceback; print(f"  [FAIL] {type(e).__name__}: {e}"); traceback.print_exc(); sys.exit(1)
    print("-"*60)
    print("[SUCCESS] 信号质量修复部署完成 — 重跑 600519:")
    print("  · 舆情/政策应给出非中性信号(从新闻解析)  · technical 计入有效信号")
    print("  · 告警不再甩锅代理, 估值/资金/板块诚实标注需国内数据通道")

if __name__ == "__main__":
    main()
